resource "aws_cloudwatch_log_group" "opensearch_search_slow_logs" {
  name              = "${local.pipeline_prefix}-${data.aws_region.current.name}-search-slow-logs"
  retention_in_days = 180
}

resource "aws_cloudwatch_log_group" "application_logs" {
  name              = "${local.pipeline_prefix}-${data.aws_region.current.name}-application-logs"
  retention_in_days = 180
}

resource "aws_cloudwatch_log_group" "audit_logs" {
  name              = "${local.pipeline_prefix}-${data.aws_region.current.name}-audit-logs"
  retention_in_days = 180
