############################################################################
#                Managed OpenSearch Domain for WAF Dashboard                   #
############################################################################
resource "aws_opensearch_domain" "regional_opensearch_domain" {
  depends_on     = [aws_acm_certificate_validation.endpoint_validation]
  domain_name    = "waf-${data.aws_region.current.name}-os"
  engine_version = var.opensearch_engine

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  advanced_security_options {
    enabled                        = true
    anonymous_auth_enabled         = false
    internal_user_database_enabled = false
    master_user_options {
      master_user_arn = var.opensearch_master_user_arn
    }
  }

  domain_endpoint_options {
    enforce_https                   = true
    tls_security_policy             = "Policy-Min-TLS-1-2-2019-07"
    custom_endpoint_enabled         = true
    custom_endpoint                 = "dashboard.waf.thepetlabco.com"
    custom_endpoint_certificate_arn = aws_acm_certificate.custom_endpoint_certificate.arn
  }

  cluster_config {
    instance_type            = lookup(var.opensearch_cluster_config, "instance_type")
    dedicated_master_count   = lookup(var.opensearch_cluster_config, "dedicated_master_count")
    dedicated_master_enabled = lookup(var.opensearch_cluster_config, "dedicated_master_enabled")
    dedicated_master_type    = lookup(var.opensearch_cluster_config, "dedicated_master_type")
    instance_count           = lookup(var.opensearch_cluster_config, "instance_count")
    warm_count               = lookup(var.opensearch_cluster_config, "warm_count")
    warm_enabled             = lookup(var.opensearch_cluster_config, "warm_enabled")
    warm_type                = lookup(var.opensearch_cluster_config, "warm_type")
    zone_awareness_enabled   = lookup(var.opensearch_cluster_config, "zone_awareness_enabled")

    dynamic "zone_awareness_config" {
      for_each = lookup(var.opensearch_cluster_config, "zone_awareness_enabled") == true ? ["1"] : []
      content {
        availability_zone_count = 2
      }

    }

    dynamic "cold_storage_options" {
      for_each = lookup(var.opensearch_cluster_config, "cold_storage_options") == true ? ["1"] : []
      content {
        enabled = lookup(var.opensearch_cluster_config, "cold_storage_options")
      }
    }
  }

  ebs_options {
    ebs_enabled = true
    volume_size = lookup(var.opensearch_cluster_config, "ebs_volume_size", 30)
    throughput  = lookup(var.opensearch_cluster_config, "ebs_volume_throughput", 250)
    volume_type = lookup(var.opensearch_cluster_config, "ebs_volume_type", "gp3")
    iops        = lookup(var.opensearch_cluster_config, "ebs_volume_iops", 3000)
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.opensearch_index_slow_logs.arn
    log_type                 = "INDEX_SLOW_LOGS"
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.opensearch_search_slow_logs.arn
    log_type                 = "SEARCH_SLOW_LOGS"
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.application_logs.arn
    log_type                 = "ES_APPLICATION_LOGS"
  }

  log_publishing_options {
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.audit_logs.arn
    log_type                 = "AUDIT_LOGS"
  }

}

############################################################################
#                   OpenSearch Saml Configuration
############################################################################
resource "aws_opensearch_domain_saml_options" "saml_configuration" {
  domain_name = aws_opensearch_domain.regional_opensearch_domain.domain_name
  saml_options {
    enabled             = lookup(var.opensearch_saml_settings, "enabled")
    master_backend_role = data.aws_iam_session_context.current.issuer_arn
    roles_key           = lookup(var.opensearch_saml_settings, "roles_key")

    idp {
      entity_id        = lookup(var.opensearch_saml_settings, "entity_id")
      metadata_content = data.aws_secretsmanager_secret_version.secret_version.secret_string
    }

  }
}

############################################################################
#                   OpenSearch Resource Policy
############################################################################

data "aws_iam_policy_document" "opensearch_resource_policy_document" {
  statement {
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions   = ["es:*"]
    resources = ["${aws_opensearch_domain.regional_opensearch_domain.arn}/*"]

  }
  statement {
    effect = "Allow"

    principals {
      type = "AWS"
      identifiers = [
        aws_iam_role.waf_kinesis_firehose_opensearch_role.arn,
        data.aws_iam_session_context.current.issuer_arn
      ]
    }

    actions   = ["es:*"]
    resources = ["${aws_opensearch_domain.regional_opensearch_domain.arn}/*", aws_opensearch_domain.regional_opensearch_domain.arn]
  }

  statement {
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions   = ["es:ESCrossClusterGet"]
    resources = ["arn:aws:es:*:538335833983:domain/waf*"]
  }
}

resource "aws_opensearch_domain_policy" "policy_doc_attach" {
  domain_name     = aws_opensearch_domain.regional_opensearch_domain.domain_name
  access_policies = data.aws_iam_policy_document.opensearch_resource_policy_document.json
}

